const PLACEHOLDER_REGEX=/@@(\w+)@@/g,PLACEHOLDER_MAP={FirstName:"givenName",LastName:"surname",JobTitle:"jobTitle",TelefonNumber:"phone",MailAddress:"mail",Address:"address"};function applyPlaceholders(e,r){return e.replace(PLACEHOLDER_REGEX,(e,a)=>{const s=PLACEHOLDER_MAP[a];return s&&null!=r[s]&&""!==r[s]?r[s]:e})}function fixCharsetMeta(e){return e.replace(/charset=windows-1252/gi,"charset=utf-8")}